example.code:
# 1. Generate in Cloudflare Dashboard: SSL/TLS → Origin Server → Create Certificate
# Hostnames: example.com, *.example.com | Validity: 15 years

# 2. Save to server
sudo mkdir -p /etc/nginx/ssl
sudo tee /etc/nginx/ssl/cloudflare-origin.pem      # paste certificate
sudo tee /etc/nginx/ssl/cloudflare-origin-key.pem  # paste private key
sudo chmod 600 /etc/nginx/ssl/cloudflare-origin-key.pem

# 3. nginx site config
server {
    listen 80;
    listen 443 ssl;
    server_name example.com;

    ssl_certificate     /etc/nginx/ssl/cloudflare-origin.pem;
    ssl_certificate_key /etc/nginx/ssl/cloudflare-origin-key.pem;
    include snippets/ssl-params.conf;

    include snippets/security-headers.conf;
    ...
}

# 4. Cloudflare Dashboard: SSL/TLS mode → Full (Strict)
